mapper.update:
UPDATE FWK_BOARD_AUTH
SET AUTH_CODE = #{authCode},
    LAST_UPDATE_DTIME = #{lastUpdateDtime},
    LAST_UPDATE_USER_ID = #{lastUpdateUserId}
WHERE USER_ID = #{userId} AND BOARD_ID = #{boardId}

UPDATE FWK_BOARD_CATEGORY
SET CATEGORY_NAME = #{categoryName}
WHERE BOARD_ID = #{boardId} AND CATEGORY_SEQ = #{categorySeq}

mapper.select:
SELECT TO_CHAR(NVL(MAX(TO_NUMBER(CATEGORY_SEQ)), 0) + 1)
FROM FWK_BOARD_CATEGORY
WHERE BOARD_ID = #{boardId}
